-- ============================================================
-- 커뮤니티/동호회/약관/다이어리 (기능 유지 — 표준 TB_ 명명 + 감사컬럼)
-- ============================================================
DROP TABLE IF EXISTS TB_CMMNTY_USER CASCADE;
DROP TABLE IF EXISTS TB_CLUB_USER CASCADE;
DROP TABLE IF EXISTS TB_CMMNTY CASCADE;
DROP TABLE IF EXISTS TB_CLUB CASCADE;
DROP TABLE IF EXISTS TB_STPLAT_INFO CASCADE;
DROP TABLE IF EXISTS TB_DIARY_INFO CASCADE;
CREATE MEMORY TABLE TB_CMMNTY (CMMNTY_ID VARCHAR(20) NOT NULL PRIMARY KEY, CMMNTY_NM VARCHAR(60), USE_AT CHAR(1), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));
CREATE MEMORY TABLE TB_CMMNTY_USER (ESNTL_ID VARCHAR(20) NOT NULL PRIMARY KEY, CMMNTY_ID VARCHAR(20), EMPLYR_ID VARCHAR(20), MNGR_AT CHAR(1), USE_AT CHAR(1), REGIST_SE_CODE VARCHAR(6), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));
CREATE MEMORY TABLE TB_CLUB (CLB_ID VARCHAR(20) NOT NULL PRIMARY KEY, CLB_NM VARCHAR(60), USE_AT CHAR(1), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));
CREATE MEMORY TABLE TB_CLUB_USER (ESNTL_ID VARCHAR(20) NOT NULL PRIMARY KEY, CLB_ID VARCHAR(20), EMPLYR_ID VARCHAR(20), OPRTR_AT CHAR(1), USE_AT CHAR(1), REGIST_SE_CODE VARCHAR(6), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));
CREATE MEMORY TABLE TB_STPLAT_INFO (USE_STPLAT_ID VARCHAR(20) NOT NULL PRIMARY KEY, USE_STPLAT_NM VARCHAR(100), USE_STPLAT_CN VARCHAR(4000), INFO_PROVD_AGRE_CN VARCHAR(4000), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));
CREATE MEMORY TABLE TB_DIARY_INFO (DIARY_ID VARCHAR(20) NOT NULL PRIMARY KEY, SCHDUL_ID VARCHAR(20), DIARY_CN VARCHAR(2500), FRST_REGIST_PNTTM TIMESTAMP, FRST_REGISTER_ID VARCHAR(20), LAST_UPDT_PNTTM TIMESTAMP, LAST_UPDUSR_ID VARCHAR(20));

